import * as React from "react";
import { cn } from "@/lib/utils";
import { type FloatingInputProps, FloatingInput } from "./floating-input";
import { FloatingLabel } from "./floating-label";

type FloatingMainProps = FloatingInputProps & {
  containerProps?: React.HTMLAttributes<HTMLDivElement>;
  label?: string;
  error?: boolean;
};

const FloatingMain = React.forwardRef<
  React.ElementRef<typeof FloatingInput>,
  React.PropsWithoutRef<FloatingMainProps>
>(({ id, label, error = false, className, containerProps, ...props }, ref) => {
  return (
    <div
      {...containerProps}
      className={cn(
        "relative",
        error &&
          "[&>*]:text-error [&>fieldset]:border-error [&>fieldset]:dark:border-error",
        containerProps?.className
      )}
    >
      <FloatingInput
        ref={ref}
        id={id}
        className={cn(
          className,
          "focus-visible:ring-ring focus-visible:ring-0 focus-visible:ring-opacity-0",
          {
            "text-error": error,
          }
        )}
        {...props}
      />
      <FloatingLabel
        htmlFor={id}
        size={props.size}
        className={cn("peer-focus:text-primary font-medium", {
          "text-error peer-focus:text-error": error,
        })}
      >
        {label}
      </FloatingLabel>
      <fieldset
        className={cn(
          "absolute peer-focus-visible:border-2 transition-all peer-focus-visible:border-primary inset-0 -top-[5px] border dark:border-input/35 border-input rounded-md m-0 py-0 text-left px-2 pointer-events-none min-w-0 peer-focus:[&>legend]:max-w-full peer-focus-visible:[&>legend]:max-w-full peer-placeholder-shown:[&>legend]:max-w-0"
        )}
      >
        <legend className="transition-all invisible whitespace-nowrap overflow-hidden w-auto max-w-full h-3 leading-4 text-xs font-normal p-0">
          <span className="px-1 visible inline-block opacity-0">{label}</span>
        </legend>
      </fieldset>
    </div>
  );
});
FloatingMain.displayName = "FloatingMain";

export { FloatingMain };

import * as React from "react";
import { cn } from "@/lib/utils";
import { cva, type VariantProps } from "class-variance-authority";

// ----------------------------------------------------------------------

const customInputVariant = cva(
  "px-3 py-2 flex leading-4 w-full text-foreground rounded-md border dark:border-input/35 border-input/65 ring-offset-background bg-transparent file:border-0 file:bg-transparent file:text-sm file:font-medium placeholder:text-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary focus-visible:ring-offset-0 focus-visible:border-0 disabled:cursor-not-allowed disabled:opacity-35",
  {
    variants: {
      size: {
        sm: "h-12 text-sm",
        md: "h-14 text-base py-4",
        lg: "h-16 text-lg",
      },
    },
    defaultVariants: {
      size: "sm",
    },
  }
);

interface FloatingInputProps
  extends Omit<React.InputHTMLAttributes<HTMLInputElement>, "size">,
    VariantProps<typeof customInputVariant> {
  size?: "sm" | "md" | "lg" | undefined;
}

const CustomInput = React.forwardRef<HTMLInputElement, FloatingInputProps>(
  ({ className, type = "text", size, ...props }, ref) => {
    return (
      <input
        type={type}
        className={cn(customInputVariant({ size, className }))}
        ref={ref}
        {...props}
      />
    );
  }
);
CustomInput.displayName = "CustomInput";

const FloatingInput = React.forwardRef<HTMLInputElement, FloatingInputProps>(
  ({ className, ...props }, ref) => {
    return (
      <CustomInput
        placeholder=" "
        className={cn("peer bg-transparent border-none", className)}
        ref={ref}
        {...props}
      />
    );
  }
);
FloatingInput.displayName = "FloatingInput";

export { FloatingInput, CustomInput, type FloatingInputProps };

import * as React from "react";
import { Label } from "@/components/ui/label";
import { cn } from "@/lib/utils";
import { cva, type VariantProps } from "class-variance-authority";

// ----------------------------------------------------------------------

const floatingLabelVariant = cva(
  "cursor-text text-muted-foreground absolute z-10 duration-300 peer-placeholder-shown:start-3 font-medium leading-4 text-xs peer-focus:text-xs start-3 peer-focus:start-3 -top-2 peer-focus:-top-2",
  {
    variants: {
      size: {
        sm: "peer-placeholder-shown:text-sm peer-placeholder-shown:top-3.5",
        md: "peer-placeholder-shown:text-base peer-placeholder-shown:top-3.5",
        lg: "peer-placeholder-shown:text-lg peer-placeholder-shown:top-4",
        textarea:
          "peer-placeholder-shown:text-base peer-placeholder-shown:top-3.5",
      },
    },
    defaultVariants: {
      size: "sm",
    },
  }
);

interface FloatingLabelProps
  extends React.ComponentPropsWithoutRef<typeof Label>,
    VariantProps<typeof floatingLabelVariant> {}

const FloatingLabel = React.forwardRef<
  React.ElementRef<typeof Label>,
  FloatingLabelProps
>(({ size = "sm", className, ...props }, ref) => {
  return (
    <Label
      className={cn(
        "select-none pointer-events-none transition-all",
        floatingLabelVariant({ size, className })
      )}
      ref={ref}
      {...props}
    />
  );
});
FloatingLabel.displayName = "FloatingLabel";

export { FloatingLabel, floatingLabelVariant, type FloatingLabelProps };
